changeSet.sql:
DO $$
DECLARE col_type text;
BEGIN
    SELECT t.typname INTO col_type
    FROM pg_attribute a
    JOIN pg_type t ON t.oid = a.atttypid
    WHERE a.attrelid = 'solicitacao_suporte'::regclass AND a.attname = 'descricao' AND a.attnum > 0 AND NOT a.attisdropped;
    IF col_type = 'oid' THEN
        ALTER TABLE solicitacao_suporte ADD COLUMN IF NOT EXISTS descricao_new TEXT;
        UPDATE solicitacao_suporte SET descricao_new = COALESCE(convert_from(lo_get(descricao::bigint), 'UTF8'), '') WHERE descricao IS NOT NULL AND descricao::bigint != 0;
        UPDATE solicitacao_suporte SET descricao_new = '' WHERE descricao_new IS NULL;
        ALTER TABLE solicitacao_suporte DROP COLUMN descricao;
        ALTER TABLE solicitacao_suporte RENAME COLUMN descricao_new TO descricao;
        ALTER TABLE solicitacao_suporte ALTER COLUMN descricao SET NOT NULL;
    ELSIF col_type = 'bytea' THEN
        ALTER TABLE solicitacao_suporte ALTER COLUMN descricao TYPE TEXT USING convert_from(descricao, 'UTF8');
    ELSIF col_type IS NOT NULL AND col_type != 'text' THEN
        ALTER TABLE solicitacao_suporte ALTER COLUMN descricao TYPE TEXT USING descricao::text;
    END IF;
END $$;

